// pages/Quiz.jsx — Scored quiz with local or AI questions
import React, { useState } from "react";
import { TOPICS } from "../data/topicsData";
import { useAI } from "../hooks/useAI";
import { saveQuizScore } from "../utils/progress";

function ScoreBadge({ score, total }) {
  const pct = Math.round((score / total) * 100);
  const color =
    pct >= 80 ? "#22c55e" : pct >= 50 ? "#f59e0b" : "#ef4444";
  const label =
    pct >= 80 ? "🎉 Excellent!" : pct >= 50 ? "📚 Good effort!" : "💪 Keep going!";

  return (
    <div
      className="glass p-6 text-center mt-6"
      style={{ border: `1px solid ${color}30` }}
    >
      <p className="text-xs font-mono text-slate-500 mb-2">YOUR SCORE</p>
      <p
        className="text-5xl font-bold mb-1"
        style={{ color, textShadow: `0 0 20px ${color}50` }}
      >
        {score}<span className="text-2xl text-slate-500">/{total}</span>
      </p>
      <p className="text-sm font-semibold" style={{ color }}>{pct}%</p>
      <p className="text-slate-400 text-sm mt-2">{label}</p>
      <div className="progress-track mt-4 max-w-xs mx-auto">
        <div className="progress-fill" style={{ width: `${pct}%`, background: color }} />
      </div>
    </div>
  );
}

export default function Quiz() {
  const [selectedSlug, setSelectedSlug] = useState(TOPICS[0].slug);
  const [questions, setQuestions]       = useState([]);
  const [answers, setAnswers]           = useState({});
  const [submitted, setSubmitted]       = useState(false);
  const [score, setScore]               = useState(0);
  const [useAIQuiz, setUseAIQuiz]       = useState(false);

  const { generateQuiz, loading, error } = useAI();
  const topic = TOPICS.find((t) => t.slug === selectedSlug);

  const startQuiz = async () => {
    setSubmitted(false);
    setAnswers({});
    setScore(0);

    if (useAIQuiz) {
      const aiQs = await generateQuiz(topic.name, 8);
      if (aiQs) setQuestions(aiQs.map((q, i) => ({ ...q, id: q.id ?? i })));
    } else {
      const local = TOPICS.flatMap((t) =>
        t.questions.map((q) => ({ ...q, id: `${t.slug}-${q.id}`, topicName: t.name }))
      );
      setQuestions(local.sort(() => Math.random() - 0.5).slice(0, 8));
    }
  };

  const handleSelect = (qId, letter) => {
    if (submitted) return;
    setAnswers((prev) => ({ ...prev, [qId]: letter }));
  };

  const handleSubmit = () => {
    if (!questions.length) return;
    let correct = 0;
    questions.forEach((q) => { if (answers[q.id] === q.answer) correct++; });
    setScore(correct);
    setSubmitted(true);
    saveQuizScore(topic.name, correct, questions.length);
  };

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">
      {/* Header */}
      <div className="mb-8 animate-fade-up">
        <span className="section-label glow-dot">Quiz Mode</span>
        <h1 className="text-2xl font-bold text-white mt-2 mb-1" style={{ letterSpacing: "-0.01em" }}>
          Take a Quiz
        </h1>
        <p className="text-slate-400 text-sm">Test your knowledge with multiple-choice questions.</p>
      </div>

      {/* Controls */}
      <div
        className="glass p-5 mb-6 animate-fade-up-d1"
        style={{ border: "1px solid rgba(99,102,241,0.15)" }}
      >
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="flex-1">
            <label className="section-label block mb-2">Topic</label>
            <select
              value={selectedSlug}
              onChange={(e) => { setSelectedSlug(e.target.value); setQuestions([]); }}
              className="input-dark"
              style={{ background: "rgba(255,255,255,0.04)" }}
            >
              {TOPICS.map((t) => (
                <option key={t.slug} value={t.slug} style={{ background: "#0f172a" }}>
                  {t.name}
                </option>
              ))}
            </select>
          </div>

          <div className="flex flex-col justify-end gap-3">
            <label
              className="flex items-center gap-2.5 cursor-pointer"
              style={{ userSelect: "none" }}
            >
              <div
                className="relative w-9 h-5 rounded-full transition-all duration-200 cursor-pointer"
                style={{ background: useAIQuiz ? "#6366f1" : "rgba(255,255,255,0.10)" }}
                onClick={() => setUseAIQuiz((v) => !v)}
              >
                <div
                  className="absolute top-0.5 left-0.5 w-4 h-4 rounded-full bg-white transition-transform duration-200"
                  style={{ transform: useAIQuiz ? "translateX(16px)" : "none" }}
                />
              </div>
              <span className="text-sm text-slate-400">AI Questions</span>
            </label>

            <button
              onClick={startQuiz}
              disabled={loading}
              className="btn-primary"
              style={{ opacity: loading ? 0.6 : 1 }}
            >
              {loading ? (
                <span className="flex items-center gap-2">
                  <span className="inline-block w-3.5 h-3.5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                  Loading…
                </span>
              ) : questions.length ? "Restart Quiz" : "Start Quiz →"}
            </button>
          </div>
        </div>

        {error && (
          <p className="mt-3 text-xs px-3 py-2 rounded-lg"
             style={{ background: "rgba(239,68,68,0.10)", color: "#fca5a5", border: "1px solid rgba(239,68,68,0.20)" }}>
            AI Error: {error}
          </p>
        )}
      </div>

      {/* Questions */}
      {questions.length > 0 && (
        <>
          <div className="flex items-center gap-3 mb-5 animate-fade-in">
            <span className="text-xs font-mono text-slate-500">{questions.length} questions</span>
            <hr className="divider flex-1" />
            <span className="text-xs font-mono text-slate-500">
              {Object.keys(answers).length}/{questions.length} answered
            </span>
          </div>

          <div className="space-y-4">
            {questions.map((q, i) => {
              const selected  = answers[q.id];
              const isCorrect = selected === q.answer;

              return (
                <div
                  key={q.id}
                  className="glass-md p-5 animate-fade-up"
                  style={{ animationDelay: `${i * 0.05}s` }}
                >
                  {q.topicName && (
                    <span className="badge badge-primary mb-2 inline-flex">{q.topicName}</span>
                  )}
                  <p className="text-sm text-slate-200 mb-4 leading-relaxed">
                    <span className="font-mono text-xs text-primary mr-2">Q{i + 1}.</span>
                    {q.question}
                  </p>

                  <div className="space-y-2">
                    {q.options.map((opt) => {
                      const letter    = opt.charAt(0);
                      const isAnswer  = letter === q.answer;
                      const isSel     = letter === selected;

                      let cls = "option-btn";
                      if (submitted) {
                        if (isAnswer)          cls += " correct";
                        else if (isSel)        cls += " wrong";
                      } else if (isSel) {
                        cls += " selected";
                      }

                      return (
                        <button
                          key={letter}
                          className={cls}
                          onClick={() => handleSelect(q.id, letter)}
                          disabled={submitted}
                        >
                          <span
                            className="inline-block w-5 h-5 rounded-md text-center text-xs font-mono font-bold mr-2 leading-5"
                            style={{ background: "rgba(255,255,255,0.06)", color: "#64748b" }}
                          >
                            {letter}
                          </span>
                          {opt.slice(3)}
                        </button>
                      );
                    })}
                  </div>

                  {submitted && (
                    <div
                      className="mt-3 p-3 rounded-xl text-xs"
                      style={{
                        background: isCorrect ? "rgba(34,197,94,0.07)" : "rgba(239,68,68,0.07)",
                        border: `1px solid ${isCorrect ? "rgba(34,197,94,0.20)" : "rgba(239,68,68,0.20)"}`,
                      }}
                    >
                      <span style={{ color: isCorrect ? "#86efac" : "#fca5a5", fontFamily: "JetBrains Mono" }}>
                        {isCorrect ? "✓ Correct" : `✗ Answer: ${q.answer}`}
                      </span>
                      {q.explanation && (
                        <p className="text-slate-400 mt-1 leading-relaxed">{q.explanation}</p>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {!submitted ? (
            <button
              onClick={handleSubmit}
              className="btn-primary mt-6 w-full sm:w-auto"
              style={{ padding: "12px 32px" }}
            >
              Submit Quiz →
            </button>
          ) : (
            <ScoreBadge score={score} total={questions.length} />
          )}
        </>
      )}

      <div className="h-16" />
    </main>
  );
}
